1	type Heading = "N" | "E" | "S" | "W";
2	
3	const LEFT_OF: Record<Heading, Heading> = { N: "W", W: "S", S: "E", E: "N" };
4	const RIGHT_OF: Record<Heading, Heading> = { N: "E", E: "S", S: "W", W: "N" };
5	const FORWARD_DELTA: Record<Heading, [number, number]> = {
6	  N: [0, 1],
7	  E: [1, 0],
8	  S: [0, -1],
9	  W: [-1, 0],
10	};
11	
12	export function execute(commands: string): string {
13	  let x = 0;
14	  let y = 0;
15	  let heading: Heading = "N";
16	  for (const command of commands) {
17	    if (command === "L") heading = LEFT_OF[heading];
18	    else if (command === "R") heading = RIGHT_OF[heading];
19	    else if (command === "F") {
20	      const [dx, dy] = FORWARD_DELTA[heading];
21	      x += dx;
22	      y += dy;
23	    }
24	  }
25	  return `${x}:${y}:${heading}`;
26	}
